#include <iostream>
#include <string>

class Scoreboard
{
    std::string m_name{};
    int m_total{};
    int m_rounds{};

public:
    Scoreboard(std::string name)
        : m_name{ name }
    {
    }

    void addScore(int points)
    {
        m_total += points;
        ++m_rounds;
    }

    int getRounds() const { return m_rounds; }
    const std::string& getName() const { return m_name; }
    int getTotal() const { return m_total; }
};

void report(const Scoreboard& sb)
{
    std::cout << "Player: " << sb.getName() << '\n';
    std::cout << "Rounds: " << sb.getRounds() << '\n';
    std::cout << "Total: " << sb.getTotal() << '\n';
}

int main()
{
    std::string name{};
    std::cin >> name;

    int n{};
    std::cin >> n;

    Scoreboard sb{ name };

    for (int i{ 0 }; i < n; ++i)
    {
        int score{};
        std::cin >> score;
        sb.addScore(score);
    }

    report(sb);

    return 0;
}
